import{_ as o,o as s,c as i,ae as r}from"./chunks/framework.C8MNLDzb.js";const m=JSON.parse('{"title":"唐诗名句","description":"","frontmatter":{},"headers":[],"relativePath":"docs/sucai/mingju/ji/唐诗.md","filePath":"docs/sucai/mingju/ji/唐诗.md"}'),n={name:"docs/sucai/mingju/ji/唐诗.md"};function l(g,t,a,e,_,c){return s(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="唐诗名句" tabindex="-1">唐诗名句 <a class="header-anchor" href="#唐诗名句" aria-label="Permalink to &quot;唐诗名句&quot;">​</a></h1><ol><li><strong>海内存知己，天涯若比邻。</strong> —— 只要世间还有知己，就算远在天涯也像近邻一样。（王勃《送杜少府之任蜀州》）</li><li><strong>落霞与孤鹜齐飞，秋水共长天一色。</strong> —— 落霞与孤雁一同飞翔，秋天的江水和天空连成一片，色彩相同。（王勃《滕王阁序》）</li><li><strong>春江潮水连海平，海上明月共潮生。</strong> —— 春天的江潮水势浩荡与大海连成一片，一轮明月从海上升起，仿佛与潮水一起涌生。（张若虚《春江花月夜》）</li><li><strong>人生代代无穷已，江月年年望相似。</strong> —— 人生一代代繁衍生息没有穷尽，江上的月亮年年地翘首仰望。（张若虚《春江花月夜》）</li><li><strong>欲穷千里目，更上一层楼。</strong> —— 想看得更远，就要再登上一层楼。（王之涣《登鹳雀楼》）</li><li><strong>羌笛何须怨杨柳，春风不度玉门关。</strong> —— 羌笛何必吹奏《折杨柳》的哀怨曲，春风是吹不到玉门关的。（王之涣《凉州词》）</li><li><strong>黄沙百战穿金甲，不破楼兰终不还。</strong> —— 在沙漠里身经百战把金甲磨穿，不攻破楼兰城誓不回还。（王昌龄《从军行》）</li><li><strong>但使龙城飞将在，不教胡马度阴山。</strong> —— 假如龙城的飞将军李广还在，绝不会让敌人的兵马越过阴山。（王昌龄《出塞》）</li><li><strong>洛阳亲友如相问，一片冰心在玉壶。</strong> —— 如果洛阳的亲友问起我，就说我依然像冰心在玉壶中一样高洁。（王昌龄《芙蓉楼送辛渐》）</li><li><strong>空山不见人，但闻人语响。返景入深林，复照青苔上。</strong> —— 空旷的山中看不见人，只听到人说话的声音。夕阳的光线射入深林，又照在青苔上面。（王维《鹿柴》）</li><li><strong>大漠孤烟直，长河落日圆。</strong> —— 广阔沙漠中一缕孤烟直冲云霄，悠长黄河边一轮落日浑圆。（王维《使至塞上》）</li><li><strong>明月松间照，清泉石上流。</strong> —— 明亮的月光洒在松林间，清澈的泉水在石头上流淌。（王维《山居秋暝》）</li><li><strong>独在异乡为异客，每逢佳节倍思亲。</strong> —— 独自一个在他乡作客，每到美好的节日就更加思念亲人。（王维《九月九日忆山东兄弟》）</li><li><strong>蜀道之难，难于上青天！</strong> —— 蜀道的艰难，比上青天还难！（李白《蜀道难》）</li><li><strong>君不见黄河之水天上来，奔流到海不复回。</strong> —— 你没看见吗？黄河的水是从天上流下来的，奔向大海一去不回来。（李白《将进酒》）</li><li><strong>人生得意须尽欢，莫使金樽空对月。天生我材必有用，千金散尽还复来。</strong> —— 人生得意时要尽情欢乐，不要让酒杯空对着月光。上天赋予我的才华必定有用，千两黄金花光了还会再回来。（李白《将进酒》）</li><li><strong>举杯邀明月，对影成三人。</strong> —— 举起酒杯邀请明月，加上影子就成三个人了。（李白《月下独酌》）</li><li><strong>安能摧眉折腰事权贵，使我不得开心颜！</strong> —— 怎么能低眉弯腰去侍奉权贵，让我不能开心地展现笑容！（李白《梦游天姥吟留别》）</li><li><strong>无边落木萧萧下，不尽长江滚滚来。</strong> —— 无边无际的树木落叶萧萧飘下，奔腾不息的长江滚滚而来。（杜甫《登高》）</li><li><strong>风急天高猿啸哀，渚清沙白鸟飞回。</strong> —— 风大天高猿猴叫声悲凉，水清沙白的洲渚上鸟儿飞回盘旋。（杜甫《登高》）</li><li><strong>艰难苦恨繁霜鬓，潦倒新停浊酒杯。</strong> —— 历尽艰难，满头白发，困顿衰颓，最近又因病断绝了酒杯。（杜甫《登高》）</li><li><strong>国破山河在，城春草木深。感时花溅泪，恨别鸟惊心。</strong> —— 国家破碎了但山河依然存在，春天来临城中草木茂盛。感伤时局花也落泪，怅恨离别鸟也惊心。（杜甫《春望》）</li><li><strong>烽火连三月，家书抵万金。</strong> —— 战争连续三个月不停，一封家信珍贵得抵得万两黄金。（杜甫《春望》）</li><li><strong>会当凌绝顶，一览众山小。</strong> —— 我一定要登上泰山顶峰，俯瞰群山，它们是那么渺小。（杜甫《望岳》）</li><li><strong>朱门酒肉臭，路有冻死骨。</strong> —— 富贵人家美酒佳肴吃不完，门外的路上却有冻饿而死的白骨。（杜甫《自京洛奉先县咏怀五百字》）</li><li><strong>正是江南好风景，落花时节又逢君。</strong> —— 正是江南风景美好的时候，在这落花的时节又碰到了你。（杜甫《江南逢李龟年》）</li><li><strong>旧时王谢堂前燕，飞入寻常百姓家。</strong> —— 从前在王导、谢安家庭厅堂前栖息的燕子，如今飞进了普通百姓家中。（刘禹锡《乌衣巷》）</li><li><strong>山不在高，有仙则名；水不在深，有龙则灵。</strong> —— 山不在于高，有仙人就著名；水不在于深，有龙就神灵。（刘禹锡《陋室铭》）</li><li><strong>千淘万漉虽辛苦，吹尽狂沙始到金。</strong> —— 经过千次万次地过滤虽然辛苦，淘尽泥沙才能得到黄金。（刘禹锡《浪淘沙》）</li><li><strong>同是天涯沦落人，相逢何必曾相识。</strong> —— 同样是流落在天涯的人，相遇何必曾经相识呢。（白居易《琵琶行》）</li><li><strong>座中泣下谁最多？江州司马青衫湿。</strong> —— 在座的人中谁流泪最多？我这个江州司马的青色官服都湿了。（白居易《琵琶行》）</li><li><strong>离离原上草，一岁一枯荣。野火烧不尽，春风吹又生。</strong> —— 原野上茂密的青草，一年一度枯萎又繁荣。野火燃烧烧不尽它，春风一吹它又重新生长。（白居易《赋得古原草送别》）</li><li><strong>日出江花红胜火，春来江水绿如蓝。</strong> —— 太阳出来，江边的花朵红得超过火焰，春天来临，江水绿得像蓝草。（白居易《忆江南》）</li><li><strong>曾经沧海难为水，除却巫山不是云。</strong> —— 曾经见过沧海的水，别处的水就不足为水了；除了巫山的云，别处的云都不能算云。（元稹《离思》）</li><li><strong>贫贱夫妻百事哀。</strong> —— 贫贱的夫妻做什么事都会感到悲哀。（元稹《遣悲怀》）</li><li><strong>春蚕到死丝方尽，蜡炬成灰泪始干。</strong> —— 春蚕直到死的时候才停止吐丝，蜡烛烧成灰后烛泪才停止流淌。比喻对感情至死不渝。（李商隐《无题》）</li><li><strong>身无彩凤双飞翼，心有灵犀一点通。</strong> —— 身上没有彩凤那双可以飞动的翅膀，心中却像灵犀一样彼此相通。（李商隐《无题》）</li><li><strong>夕阳无限好，只是近黄昏。</strong> —— 夕阳的景色美到了极致，可惜已经接近黄昏了。（李商隐《乐游原》）</li><li><strong>何当共剪西窗烛，却话巴山夜雨时。</strong> —— 什么时候我们能一起剪去西窗下的烛芯，细说巴山夜雨时的情景。（李商隐《夜雨寄北》）</li><li><strong>锦瑟无端五十弦，一弦一柱思华年。</strong> —— 华美的瑟为什么会有五十根弦，每一根弦都让我思念逝去的年华。（李商隐《锦瑟》）</li></ol>',2)])])}const u=o(n,[["render",l]]);export{m as __pageData,u as default};
